import React, { useState, useMemo } from 'react';
import { useAppContext } from '../context/AppContext';
import { LockIcon, MenuIcon, DollarSignIcon, ChartIcon, CheckIcon, DownloadIcon } from '../constants';
import { Capacitor } from '@capacitor/core';
import { Filesystem, Directory, Encoding } from '@capacitor/filesystem';
import { Share } from '@capacitor/share';

// --- TYPES ---
type DateFilter = 'today' | 'yesterday' | 'week' | 'month' | 'custom';
type ReportTab = 'overview' | 'items' | 'orders'; // Removed 'categories'
type SortConfig = { key: string; direction: 'asc' | 'desc' };

interface Metrics {
  totalSales: number;
  totalOrders: number;
  avgOrderValue: number;
  paymentMethods: Record<string, number>;
  topItems: { name: string, count: number, revenue: number }[];
  allItems: { name: string, count: number, revenue: number, category: string }[];
  salesByHour: Record<number, number>;
  salesByCategory: Record<string, number>;
}

// --- COMPONENT: REPORT STAT CARD ---
